const input = $input.first().json.body ?? $input.first().json;
function createLeadId() {
  if (globalThis.crypto?.randomUUID) {
    return `lead_${globalThis.crypto.randomUUID()}`;
  }
  return `lead_${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
}
const lead = {
  lead_id: input.lead_id ?? createLeadId(),
  source: input.source,
  received_at: input.received_at ?? new Date().toISOString(),
  contact: {
    name: input.name ?? null,
    email: input.email ?? null,
    phone: input.phone ?? null,
    company: input.company ?? null
  },
  content: {
    message: input.message ?? null,
    transcript: input.transcript ?? null
  },
  metadata: {
    campaign: input.campaign ?? null,
    language: input.language ?? 'en',
    external_id: input.external_id ?? null
  },
  raw_input: input
};
return [{ json: { lead, raw_input: input } }];

const data = $input.first().json;
const lead = data.lead;
const errors = [];
if (!['website_form', 'facebook_ad', 'missed_call_transcript'].includes(lead.source)) errors.push('UNSUPPORTED_SOURCE');
if (!lead.contact.email && !lead.contact.phone) errors.push('MISSING_CONTACT_METHOD');
if (!lead.content.message && !lead.content.transcript) errors.push('MISSING_MESSAGE_CONTENT');
if (errors.length > 0) {
  return [{
    json: {
      status: 'error',
      error: {
        code: errors[0],
        message: 'Lead input failed validation.',
        details: { errors }
      },
      raw_input: data.raw_input
    }
  }];
}
return [{ json: data }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const lead = data.lead;
const text = `${lead.content.message ?? ''} ${lead.content.transcript ?? ''}`.toLowerCase();
let output;
if (text.includes('spam') || text.includes('unsubscribe') || text.includes('crypto giveaway')) {
  output = {
    lead_summary: 'The message appears to be spam or not a legitimate service inquiry.',
    lead_type: 'Spam',
    intent: 'Other',
    priority: 'Low',
    lead_score: 22,
    service_requested: null,
    pain_point: null,
    recommended_next_step: 'Review manually only if additional context appears.',
    needs_human_followup: false,
    suggested_email_reply: 'Hi, thanks for reaching out. Please send more detail about the service you need so we can route your request correctly.',
    suggested_sms_reply: 'Thanks for reaching out. Please send more detail about the service you need.',
    crm_fields: {
      pipeline_stage: 'Spam',
      lead_source: lead.source,
      interest_area: null,
      follow_up_status: 'No Action'
    }
  };
} else if (text.includes('book') || text.includes('booking') || text.includes('appointment') || text.includes('consultation') || text.includes('quote') || text.includes('call me back')) {
  output = {
    lead_summary: 'The lead wants help with booking, quoting, or follow-up automation.',
    lead_type: 'Sales Inquiry',
    intent: lead.content.transcript ? 'Request Quote' : 'Book Consultation',
    priority: 'High',
    lead_score: 86,
    service_requested: lead.content.transcript ? 'Service quote' : 'Appointment booking automation',
    pain_point: 'Manual scheduling and delayed follow-up',
    recommended_next_step: 'Send a booking link and ask about current scheduling tools.',
    needs_human_followup: true,
    suggested_email_reply: 'Hi, thanks for reaching out. I can help review your booking and follow-up process. Could you share what tools you currently use?',
    suggested_sms_reply: 'Hi, thanks for reaching out. I can help with booking and follow-up automation. Would you like to schedule a quick consultation?',
    crm_fields: {
      pipeline_stage: 'New Qualified Lead',
      lead_source: lead.source,
      interest_area: 'Automation consulting',
      follow_up_status: 'Draft Created'
    }
  };
} else {
  output = {
    lead_summary: 'The lead shows general interest in automation.',
    lead_type: 'Sales Inquiry',
    intent: 'Ask Question',
    priority: 'Medium',
    lead_score: 58,
    service_requested: 'Customer follow-up automation',
    pain_point: 'Manual follow-up process',
    recommended_next_step: 'Ask about current follow-up volume and target response time.',
    needs_human_followup: false,
    suggested_email_reply: 'Hi, thanks for reaching out. I can help review your current follow-up process and identify automation opportunities.',
    suggested_sms_reply: 'Hi, thanks for your interest. Could you share your current lead volume and follow-up process?',
    crm_fields: {
      pipeline_stage: 'New Lead',
      lead_source: lead.source,
      interest_area: 'Automation consulting',
      follow_up_status: 'Needs Review'
    }
  };
}
return [{ json: { ...data, ai_gateway_response: { provider: 'mock', model: 'demo-leadops-model', output, usage: { input_tokens: 0, output_tokens: 0 } } } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const output = data.ai_gateway_response.output;
const required = ['lead_summary', 'lead_type', 'intent', 'priority', 'lead_score', 'recommended_next_step', 'suggested_email_reply', 'suggested_sms_reply', 'crm_fields'];
const missing = required.filter((field) => output[field] === undefined || output[field] === null);
if (missing.length > 0 || output.lead_score < 0 || output.lead_score > 100) {
  return [{
    json: {
      status: 'error',
      error: {
        code: 'AI_SCHEMA_VALIDATION_FAILED',
        message: 'Mock AI output failed schema validation.',
        details: { missing }
      },
      raw_ai_output: output,
      raw_input: data.raw_input
    }
  }];
}
return [{ json: data }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const lead = data.lead;
const output = data.ai_gateway_response.output;
const statusByFollowUp = {
  'Draft Created': 'DRAFT_CREATED',
  'Needs Review': 'NEEDS_REVIEW',
  'No Action': 'NO_ACTION'
};
const crm = {
  lead_id: lead.lead_id,
  received_at: lead.received_at,
  source: lead.source,
  name: lead.contact.name,
  email: lead.contact.email,
  phone: lead.contact.phone,
  company: lead.contact.company,
  lead_type: output.lead_type,
  intent: output.intent,
  priority: output.priority,
  lead_score: output.lead_score,
  service_requested: output.service_requested,
  pain_point: output.pain_point,
  lead_summary: output.lead_summary,
  recommended_next_step: output.recommended_next_step,
  pipeline_stage: output.crm_fields.pipeline_stage,
  follow_up_status: output.crm_fields.follow_up_status,
  email_draft: output.suggested_email_reply,
  sms_draft: output.suggested_sms_reply,
  booking_link: null,
  status: statusByFollowUp[output.crm_fields.follow_up_status] ?? 'NEEDS_REVIEW',
  error_code: null
};
return [{ json: { ...data, crm_record: crm } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const crm = data.crm_record;
const slack_alert = crm.lead_score >= 75 ? {
  channel: '#sales',
  text: `High-priority lead: ${crm.name ?? crm.phone ?? crm.email}`,
  fields: {
    lead_id: crm.lead_id,
    company: crm.company,
    source: crm.source,
    priority: crm.priority,
    lead_score: crm.lead_score,
    intent: crm.intent,
    recommended_next_step: crm.recommended_next_step
  }
} : null;
return [{ json: { ...data, slack_alert } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const crm = data.crm_record;
const gmail_draft = crm.email ? {
  to: crm.email,
  subject: `Re: ${crm.service_requested ?? 'Your inquiry'}`,
  body: crm.email_draft
} : null;
return [{ json: { ...data, gmail_draft } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const crm = data.crm_record;
const sms_draft = crm.phone ? {
  phone: crm.phone,
  body: crm.sms_draft,
  status: 'draft_created'
} : null;
return [{ json: { ...data, sms_draft } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const booking_link = data.ai_gateway_response.output.intent === 'Book Consultation' ? 'https://calendly.com/demo/intro-call' : null;
const gmail_draft = data.gmail_draft && booking_link ? { ...data.gmail_draft, body: `${data.gmail_draft.body}\n\nBooking link: ${booking_link}` } : data.gmail_draft;
const crm_record = {
  ...data.crm_record,
  booking_link,
  email_draft: gmail_draft ? gmail_draft.body : data.crm_record.email_draft
};
return [{ json: { ...data, booking_link, gmail_draft, crm_record } }];

const data = $input.first().json;
if (data.status === 'error') return [{ json: data }];
const crm = data.crm_record;
return [{
  json: {
    status: 'success',
    lead_id: crm.lead_id,
    priority: crm.priority,
    lead_score: crm.lead_score,
    crm_record_created: true,
    slack_alert_sent: Boolean(data.slack_alert),
    gmail_draft_created: Boolean(data.gmail_draft),
    sms_draft_created: Boolean(data.sms_draft),
    booking_link_attached: Boolean(data.booking_link),
    next_step: 'Review the generated drafts and contact the lead.',
    demo_outputs: {
      crm_record: crm,
      slack_alert: data.slack_alert,
      gmail_draft: data.gmail_draft,
      sms_draft: data.sms_draft,
      booking_link: data.booking_link
    }
  }
}];
